"use client";
import { useState, useEffect } from 'react';
import Link from 'next/link';
import { Rocket, Filter, Search, ArrowRight, GitCommit } from 'lucide-react';
import { getStoredData, saveStoredData, Deployment } from '@/lib/mockData';
import { getAuthToken } from '@/lib/session';

export default function DeploymentsPage() {
  const [deployments, setDeployments] = useState<Deployment[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [envFilter, setEnvFilter] = useState('all');

  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function load() {
      try {
        const token = getAuthToken();
        const headers: Record<string, string> = token ? { Authorization: `Bearer ${token}` } : {};
        const res = await fetch('/api/deployments?per_page=100', { headers });
        if (!res.ok) throw new Error('API unavailable');
        const json = await res.json();
        const apiDeployments: Deployment[] = (json.data ?? []).map((d: any) => ({
          id: d.id,
          service: d.service?.name ?? d.service?.slug ?? d.service_id,
          version: d.version,
          risk: d.risk_score ?? 0,
          // Map environment name to status field (how the UI displays it)
          status: d.environment?.name
            ? (d.environment.name.charAt(0).toUpperCase() + d.environment.name.slice(1))
            : 'Dev',
          time: new Date(d.created_at ?? d.started_at ?? Date.now()).toLocaleString(),
          deployer: d.deployed_by_name ?? '@unknown',
          changeSummary: d.change_summary ?? '',
          commit: d.commit_sha ?? '',
          ticket: d.ticket_url ?? '',
          infraChanged: false,
          infraSummary: '',
          timestamp: d.created_at ?? d.started_at ?? new Date().toISOString(),
        }));
        setDeployments(apiDeployments);
        saveStoredData({ deployments: apiDeployments });
      } catch {
        setDeployments(getStoredData().deployments);
      } finally {
        setLoading(false);
      }
    }
    load();
  }, []);

  const filtered = deployments.filter(d => {
    const matchesSearch = d.service.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          d.version.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          d.changeSummary.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesEnv = envFilter === 'all' || d.status === envFilter;
    return matchesSearch && matchesEnv;
  });

  return (
    <div className="p-8 space-y-8 animate-fade-in max-w-5xl mx-auto">
      
      {/* Header */}
      <header className="flex flex-col sm:flex-row justify-between items-start sm:items-end gap-4">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-[#F0F2FF]">Logged Deployments</h1>
          <p className="text-xs text-[#8B91B5] mt-1">Review calculated risk and changesets across past deployment pipelines</p>
        </div>
      </header>

      {/* Filters & Search */}
      <div className="flex flex-col sm:flex-row gap-4 items-center">
        {/* Search */}
        <div className="relative w-full sm:w-80">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[#8B91B5]" />
          <input
            type="text"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            placeholder="Search by service or summary..."
            className="w-full bg-[#13161E] border border-[#2A2F45] rounded-xl pl-9 pr-4 py-2 text-xs text-[#F0F2FF] placeholder-[#4A5070] focus:outline-none focus:border-[#4F7FFF]"
          />
        </div>

        {/* Environment Filter */}
        <div className="flex items-center gap-1.5 bg-[#13161E] border border-[#2A2F45] rounded-xl px-3 py-2 w-full sm:w-auto">
          <Filter size={12} className="text-[#8B91B5]" />
          <select 
            value={envFilter}
            onChange={(e) => setEnvFilter(e.target.value)}
            className="bg-transparent text-xs text-[#F0F2FF] focus:outline-none pr-4 w-full"
          >
            <option value="all">All Environments</option>
            <option value="Dev">Dev</option>
            <option value="Staging">Staging</option>
            <option value="Production">Production</option>
          </select>
        </div>
      </div>

      {/* Table grid */}
      <div className="card-bg rounded-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-xs border-collapse">
            <thead>
              <tr className="border-b border-[#2A2F45] text-[#8B91B5] bg-[#0D0F14]/25">
                <th className="px-6 py-4 font-bold uppercase tracking-wider">Service</th>
                <th className="px-6 py-4 font-bold uppercase tracking-wider">Version</th>
                <th className="px-6 py-4 font-bold uppercase tracking-wider">Env</th>
                <th className="px-6 py-4 font-bold uppercase tracking-wider">Change Details</th>
                <th className="px-6 py-4 font-bold uppercase tracking-wider">Risk Score</th>
                <th className="px-6 py-4 font-bold uppercase tracking-wider">Inspect</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-[#2A2F45]/50">
              {filtered.map((d) => {
                const isProd = d.status.toLowerCase() === 'production';
                const envColor = isProd ? 'text-[#22C55E] bg-[#22C55E]/10' : 'text-[#4F7FFF] bg-[#4F7FFF]/10';

                return (
                  <tr key={d.id} className="hover:bg-[#1C2030]/20 transition-colors">
                    <td className="px-6 py-4 font-bold text-[#F0F2FF]">{d.service}</td>
                    <td className="px-6 py-4 font-mono font-bold text-[#8B91B5]">{d.version}</td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-0.5 rounded text-[9px] font-bold ${envColor}`}>
                        {d.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-[#8B91B5] max-w-xs truncate">{d.changeSummary}</td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-0.5 rounded text-xs font-bold font-mono ${
                        d.risk > 80 ? 'text-[#EF4444] bg-[#EF4444]/10' :
                        d.risk > 60 ? 'text-[#F97316] bg-[#F97316]/10' :
                        d.risk > 30 ? 'text-[#EAB308] bg-[#EAB308]/10' :
                        'text-[#22C55E] bg-[#22C55E]/10'
                      }`}>
                        {d.risk}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <Link 
                        href={`/deployments/${d.id}`}
                        className="text-[#4F7FFF] hover:underline font-bold"
                      >
                        Inspect
                      </Link>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

    </div>
  );
}
